external_knowledge:
- 'groove and sound signatures' refers to 'danceability' and 'acousticness' scores; 
- 'stand out from the crowd' means having an average popularity score greater than the overall average popularity score of tracks in the top 200; 
- 'top charts' refers to tracks with 'top200 = 1'; 
- 'average fame of the entire top 200' refers to the overall average popularity score of tracks in the top 200.

sql:
SELECT track_id, energy, tempo
FROM track_features
ORDER BY energy DESC;
